class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize pieces on the board
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = Piece('black')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('white')

    def is_valid_move(self, start, end):
        # Check if a move is valid based on game rules
        piece = self.board[start[0]][start[1]]
        dx, dy = abs(end[0] - start[0]), abs(end[1] - start[1])
        if dx != 1 or dy != 1:
            return False
        if self.board[end[0]][end[1]] is not None:
            return False
        if piece.color == 'black':
            return start[0] > end[0]
        else:
            return start[0] < end[0]

    def move(self, start, end):
        # Update piece position on the board
        self.board[end[0]][end[1]] = self.board[start[0]][start[1]]
        self.board[start[0]][start[1]] = None
